var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"평소보다 필사적으로 변한 것은 어째서일까.","JPN":"普段より必死になったのはなぜなのか。","ENG":"Why am I more desperate than usual?","TWN":"變得比平時更拼命是為什麼呢？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"과거의 삶과 겹쳐 보인 사람들에 대한 연민인가?","JPN":"過去の人生と重なって見えた人々への同情？","ENG":"Is it sympathy for the people who remind me of my past?","TWN":"是因為同情那些與我過去的生活有類似經歷的人嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"<color=#ffd34c>사회에서 벗어나 새로운 삶을 시작하려는 이들이 종종 이곳을 찾아오지요. </color>","JPN":"<color=#ffd34c>社会から外れ、新しい人生を始めようとする者が時々ここへやってくるのです。</color>","ENG":"<color=#ffd34c>So it is sometimes sought by those who wish to escape society and start a new life.</color>","TWN":"<color=#ffd34c>所以經常有離開社會尋找新生活的人來這裡。</color>"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L6_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"<color=#ffd34c>남은 사람은 노예 출신이거나 갈 곳 없는 토착민들입니다</color>.","JPN":"<color=#ffd34c>残ったのは奴隷出身か、他に行くあてのない土着民です。</color>","ENG":"<color=#ffd34c>Everyone who could leave already left. The ones remaining are former slaves or natives.</color>","TWN":"<color=#ffd34c>剩下都是奴隸或無處可去的主著。</color>"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"narration","speaker":null,"text":{"KOREA":"그게 아니라면, 성녀로서의 소임을 다하기 위함인가?","JPN":"それとも、聖女としての役割を果たすため？","ENG":"Or is it my desire to fulfill my duty as a Saintess?","TWN":"若非如此，難道是為了履行聖女的使命？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHILDREN_MEMORIAL_NULL_C","text":{"KOREA":"저는 성녀님처럼 되는 게 꿈이거든요.","JPN":"私は聖女様みたいになるのが夢なんです。","ENG":"I want to be like you when I grow up.","TWN":"我的夢想是想跟聖女一樣。"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHILDREN_MEMORIAL_NULL_C","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L11_1","type":"dialog","speaker":"CHILDREN_MEMORIAL_NULL_C","text":{"KOREA":"마왕 같은 건 한 주먹거리도 안 돼요! 그렇죠, 성녀님?","JPN":"魔王なんかは一発でやっつけられますよね！　ね？　聖女様！","ENG":"That Demon Lord won't stand a chance against you! Right, Your Holiness?","TWN":"你一拳就可以打倒魔王對吧！聖女？"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHILDREN_MEMORIAL_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"narration","speaker":null,"text":{"KOREA":"어느 쪽이든 상관없어.","JPN":"どちらだろうと関係ない。","ENG":"It doesn't matter.","TWN":"無論是哪一種都無所謂。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"narration","speaker":null,"text":{"KOREA":"중요한 건.","JPN":"大事なのは。","ENG":"What matters is.","TWN":"重要的是。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":"말했잖아. 구해 주겠다고.","JPN":"言ったでしょ。救ってあげるって。","ENG":"I promised you, that I would save you.","TWN":"我不是跟你說過嗎？我會救你的。"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L21_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":"이 지팡이는 이제 네 거야, 루크레시아.","JPN":"この杖はもう君のものだよ、ルクレシア。","ENG":"This staff is now yours, Lucrecia.","TWN":"這個杖，現在是你的了，露可蕾西亞。"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ffd34c>내가, 그분이 택한 성녀라는 것</color>.","JPN":"<color=#ffd34c>私は、あの方の選んだ聖女なんだから。</color>","ENG":"<color=#ffd34c>I am the Saintess that he chose.</color>","TWN":"<color=#ffd34c>我是被那位選中的聖女。</color>"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"고생했어. 루크레시아.","JPN":"お疲れ様、ルクレシア。","ENG":"Good job, Lucrecia.","TWN":"辛苦了，露可蕾西亞。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"괴수들은 모두 쓰러졌어. 더는 걱정하지 않아도 돼.","JPN":"怪獣は全部倒した。もう心配しなくても大丈夫だよ。","ENG":"The monsters are all dead. You don't need to worry anymore.","TWN":"不用擔心，怪獸都死了。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"HOLY_MEMORIAL_NPC_NULL","text":{"KOREA":"…구원자님?","JPN":"……救世主様？","ENG":"...Savior?","TWN":"…救贖者大人？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_MEMORIAL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"HOLY_MEMORIAL_NPC_NULL","text":{"KOREA":"나는… 분명…….","JPN":"私は……確か……","ENG":"I thought... I...","TWN":"我…明明…"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_MEMORIAL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HOLY_MEMORIAL_NPC_NULL","text":{"KOREA":"…아.","JPN":"……あ。","ENG":"...Oh.","TWN":"……對了。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_MEMORIAL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"HOLY_MEMORIAL_NPC_NULL","text":{"KOREA":"마을. 마을은요?","JPN":"村。村は？","ENG":"The village. What about the village?","TWN":"村子呢？村子怎麼樣了？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_MEMORIAL_NPC_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L48_1","type":"dialog","speaker":"HOLY_MEMORIAL_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_MEMORIAL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"HOLY_MEMORIAL_NPC_NULL","text":{"KOREA":"죄송… 해요. 잘 해보려고 했는데.","JPN":"すみま……せん。お役目を果たそうとしたのですが。","ENG":"I'm... sorry. I tried to make it work.","TWN":"對不起…我已經盡力了。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_MEMORIAL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"HOLY_MEMORIAL_NPC_NULL","text":{"KOREA":"역시, 천한 노예가 성녀를 연기해봤자인 걸까요…?","JPN":"やはり、卑しい奴隷が聖女を演じたところで、どうにもならないのでしょうか……？","ENG":"But I guess it's pointless for a lowly slave to act like a Saintess...","TWN":"果然，卑賤的奴隸還是無法把聖女的角色扮演好嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_MEMORIAL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L3_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"그렇지 않아.","JPN":"そんなことない。","ENG":"No.","TWN":"不是的。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HOLY_MEMORIAL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"루크레시아는 최선을 다했어.","JPN":"ルクレシアはよく頑張ったよ。","ENG":"You did your best, Lucrecia.","TWN":"露可蕾西亞，你已經盡力了。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HOLY_MEMORIAL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L5_1","type":"dialog","speaker":"HOLY_MEMORIAL_NPC_NULL","text":{"KOREA":"…상냥하시네요, 구원자 님은.","JPN":"……優しいですね、救世主様は。","ENG":"...You are too kind, Savior.","TWN":"……救贖者大人，你真善良。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HOLY_MEMORIAL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"HOLY_MEMORIAL_NPC_NULL","text":{"KOREA":"분명, 처음 만났을 때도 그랬었죠.","JPN":"確か、初めて会った時もそうでした。","ENG":"It was the same when I first met you.","TWN":"初次見面時也是這樣。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HOLY_MEMORIAL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"HOLY_MEMORIAL_NPC_NULL","text":{"KOREA":"처음 만난 절 위해 전하와 싸우고, 지팡이를 건네며 성녀로 지목해 주셨어요.","JPN":"初めて会った私のために殿下と戦ってくださり、杖を渡しながら私を聖女だと言ってくれましたよね。","ENG":"You fought His Highness for a stranger like me, and named me the Saintess as you handed me the staff.","TWN":"初次見面時，您為了我與殿下交手，將拐杖交給我，指名我為聖女。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HOLY_MEMORIAL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"루크레시아. 네 잘못이 아니야.","JPN":"ルクレシア。君は悪くないよ。","ENG":"Lucrecia. You are not to blame.","TWN":"露可蕾西亞，這不是你的錯。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HOLY_MEMORIAL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"HOLY_MEMORIAL_NPC_NULL","text":{"KOREA":"……저. 구원자님께서 지팡이를 건내 주셨을 때 정말 기뻤어요.","JPN":"……私。救世主様が杖を渡してくださったとき、本当に嬉しかったんです。","ENG":"...I. I was really happy when you handed me the staff.","TWN":"……救贖者大人，當您將拐杖交給我時，我真的很高興。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_MEMORIAL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HOLY_MEMORIAL_NPC_NULL","text":{"KOREA":"할아버지의 말처럼, 내게도 구원이 찾아왔다고.","JPN":"お爺さんの言うとおり、私にも救いがやって来たんだって。","ENG":"Like my grandfather said, I thought I was saved.","TWN":"如同爺爺所說，救贖也臨到我身上。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_MEMORIAL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HOLY_MEMORIAL_NPC_NULL","text":{"KOREA":"나만 잘한다면 동화 속 이야기처럼 행복한 결말을 맞이할 수 있을 거라고…","JPN":"努力次第では、おとぎ話のように幸せな結末を迎えることができるって……","ENG":"I thought that, if I tried hard enough, I could have my happy ending...","TWN":"只要我表現好，就能像童話故事一樣有個幸福的結局……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_MEMORIAL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HOLY_MEMORIAL_NPC_NULL","text":{"KOREA":"예법을 배우고… 남들이 바라는 대로 행동하고. 말투까지 바꿨는데….","JPN":"礼法を教わって……みんなの望むとおりに行動して。口調まで変えたのに……","ENG":"So I learned proper manners... I did what others wanted me to do. I changed how I spoke...","TWN":"學習禮儀…照別人期待行事，甚至改變說話方式…"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_MEMORIAL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HOLY_MEMORIAL_NPC_NULL","text":{"KOREA":"이렇게까지 했는데….","JPN":"ここまでしたのに……","ENG":"I did all that...","TWN":"我做成這樣…"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_MEMORIAL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"HOLY_MEMORIAL_NPC_NULL","text":{"KOREA":"저는 계속… 당신에게 아무런 도움도……","JPN":"私はずっと……あなたに何も……","ENG":"But I still... couldn't be of any use to you...","TWN":"結果…我還是無法幫到您…"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_MEMORIAL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"HOLY_MEMORIAL_NPC_PIN","text":{"KOREA":"구원자님?","JPN":"救世主様？","ENG":"Savior?","TWN":"救贖者大人？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_MEMORIAL_NPC_PIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HOLY_MEMORIAL_NPC_PIN","text":{"KOREA":"이건…?","JPN":"これは……？","ENG":"That's...","TWN":"這是…？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_MEMORIAL_NPC_PIN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"촌장님이 그랬는데, 선별된 남성은 상대 여성에게 장신구를 선물한다는 풍습이 있다더라.","JPN":"村長に聞いたんだけど、選ばれた男性は相手の女性にアクセサリーをプレゼントする風習があるんだって。","ENG":"The chief mentioned the tradition of the selected man giving his partner an accessory.","TWN":"村長說過，按照習俗，被選上的男方要贈送飾品女方。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_MEMORIAL_NPC_PIN","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"직접 만든 머리핀인데, 루크레시아의 마음에 들었으면 좋겠네.","JPN":"このヘアピン、僕が作ったんだ。ルクレシアが気に入ってくれるといいけど。","ENG":"I made this hair pin myself. I hope you like it, Lucrecia.","TWN":"這是我親手做的髮夾，希望你會喜歡。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HOLY_MEMORIAL_NPC_PIN","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"HOLY_MEMORIAL_NPC_PIN","text":{"KOREA":"하, 하지만. 축제는 이미 끝나버렸는걸요.","JPN":"で、でも。お祭りはもうできなくなってしまったんです。","ENG":"B-but. The festival is already over.","TWN":"可，可是，慶典已經結束了。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HOLY_MEMORIAL_NPC_PIN","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"HOLY_MEMORIAL_NPC_PIN","text":{"KOREA":"제가 무능한 탓에….","JPN":"私が無能なせいで……","ENG":"Because of my incompetence...","TWN":"都怪我無能…"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HOLY_MEMORIAL_NPC_PIN","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"으음. 확실히 이런 상황에서 축제를 이어가는 건 무리일려나.","JPN":"うーん。確かにこんな状況でお祭りを続けるのは無理かな。","ENG":"Hmm. I guess it's a stretch to continue the festival in a situation like this.","TWN":"嗯。在這種情況下，慶典確實很難繼續下去。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HOLY_MEMORIAL_NPC_PIN","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"그럼 축제나 제와는 상관없이 말할게.","JPN":"じゃあ、お祭りとか祭祀とかは抜きにして言うね。","ENG":"Then I'd like to say this outside of the festival and rite.","TWN":"那麼，雖然與慶典和祭祀無關，"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_MEMORIAL_NPC_PIN","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"루크레시아.","JPN":"ルクレシア。","ENG":"Lucrecia.","TWN":"露可蕾西亞。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L36_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"나와 춤춰줄 수 있을까?","JPN":"僕と一緒に踊ってくれる？","ENG":"May I have this dance?","TWN":"你願意和我跳一支舞嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HOLY_MEMORIAL_NPC_PIN","text":{"KOREA":"…아.","JPN":"……あ。","ENG":"...Oh.","TWN":"我…"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_MEMORIAL_NPC_PIN","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L39_1","type":"dialog","speaker":"HOLY_MEMORIAL_NPC_PIN","text":{"KOREA":"저, 저는.","JPN":"わ、私は……","ENG":"I-I.","TWN":"我…"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_MEMORIAL_NPC_PIN","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"HOLY_MEMORIAL_NPC_PIN","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_MEMORIAL_NPC_PIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"HOLY_MEMORIAL_NPC_PIN","text":{"KOREA":"네.","JPN":"はい。","ENG":"Yes.","TWN":"願意。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_MEMORIAL_NPC_PIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"HOLY_MEMORIAL_NPC_PIN","text":{"KOREA":"……부디.","JPN":"……どうか。","ENG":"...Of course.","TWN":"……很願意。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_MEMORIAL_NPC_PIN","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};